const rawMobile = {{workflowparams:mobile_number}};

// Normalize mobile input into an array of trimmed, non-empty strings.
let mobileList = [];
if (Array.isArray(rawMobile)) {
  mobileList = rawMobile;
} else if (rawMobile != null && rawMobile !== "") {
  mobileList = [rawMobile];
}
mobileList = mobileList
  .map((m) => (m == null ? "" : String(m)).trim())
  .filter((m) => m !== "");

const lookupBy = mobileList.length > 0 ? "phone" : "email";

// SE Asia dialing rules. cc = country calling code; nationalRe matches the
// national subscriber number (no code, no leading 0); hasNationalZero = the
// number is commonly written with a leading 0 domestically.
const COUNTRIES = [
  { cc: "60", nationalRe: /^1\d{8,9}$/, hasNationalZero: true },
  { cc: "65", nationalRe: /^[89]\d{7}$/, hasNationalZero: false },
  { cc: "66", nationalRe: /^[689]\d{8}$/, hasNationalZero: true },
  { cc: "62", nationalRe: /^8\d{8,11}$/, hasNationalZero: true }
];

// Broad set of stored representations, used only to cast the IN-query net.
// This intentionally over-fetches (e.g. a bare national number matches every
// contact storing those digits regardless of country); the Build Customer IDs
// node then disambiguates using each contact's calling_code.
const buildVariants = (mobileStr) => {
  const variants = new Set();
  if (!mobileStr) return [];
  variants.add(mobileStr);
  const stripped = mobileStr.startsWith("+") ? mobileStr.slice(1) : mobileStr;
  variants.add(stripped);

  const emit = (cc, national, hasZero) => {
    if (!national) return;
    variants.add(national);
    if (hasZero && !national.startsWith("0")) variants.add("0" + national);
    if (cc) {
      variants.add(cc + national);
      variants.add("+" + cc + national);
    }
  };

  for (const c of COUNTRIES) {
    if (stripped.startsWith(c.cc) && stripped.length > c.cc.length) {
      emit(c.cc, stripped.slice(c.cc.length), c.hasNationalZero);
    }
  }

  if (stripped.startsWith("0") && stripped.length > 1) {
    const national = stripped.slice(1);
    variants.add(national);
    for (const c of COUNTRIES) {
      if (c.hasNationalZero && c.nationalRe.test(national)) emit(c.cc, national, true);
    }
  } else {
    for (const c of COUNTRIES) {
      if (c.nationalRe.test(stripped)) emit(c.cc, stripped, c.hasNationalZero);
    }
  }

  return Array.from(variants);
};

// Canonical "full international digits" the input could mean. Country-code
// qualified when one can be inferred (explicit code, or a leading-0/national
// number matching a country's pattern); falls back to the bare national only
// when no code is inferable. This is what disambiguates two contacts that
// share a national number but differ by calling_code.
const inputIntlForms = (mobileStr) => {
  const forms = new Set();
  if (!mobileStr) return [];
  const stripped = mobileStr.startsWith("+") ? mobileStr.slice(1) : mobileStr;
  let coded = false;

  for (const c of COUNTRIES) {
    if (stripped.startsWith(c.cc) && stripped.length > c.cc.length) {
      forms.add(c.cc + stripped.slice(c.cc.length));
      coded = true;
    }
  }

  if (stripped.startsWith("0") && stripped.length > 1) {
    const national = stripped.slice(1);
    for (const c of COUNTRIES) {
      if (c.hasNationalZero && c.nationalRe.test(national)) { forms.add(c.cc + national); coded = true; }
    }
  } else if (!stripped.startsWith("0")) {
    for (const c of COUNTRIES) {
      if (c.nationalRe.test(stripped)) { forms.add(c.cc + stripped); coded = true; }
    }
  }

  if (!coded) forms.add(stripped); // no code inferable -> bare national only
  return Array.from(forms);
};

const inputMap = [];
const allVariantsSet = new Set();
for (const input of mobileList) {
  const variants = buildVariants(input);
  inputMap.push({ input, variants, intlForms: inputIntlForms(input) });
  for (const v of variants) allVariantsSet.add(v);
}
const allVariants = Array.from(allVariantsSet);

return { lookupBy, allVariants, inputMap };

const phoneContacts = {{node:get_node_THuA8VPh.data.data}} || [];
const emailRes = {{node:get_node_814fnfzT.data}};
const lookupBy = {{node:code_node_yrSiOiir.data.lookupBy}};
const inputMap = {{node:code_node_yrSiOiir.data.inputMap}};

// get-node (email branch) data is a single object when count===1, an array otherwise.
const getNodeToArray = (res) => {
  if (!res || !res.count || res.count <= 0) return [];
  const dd = res.data;
  if (Array.isArray(dd)) return dd;
  if (dd && typeof dd === "object") return [dd];
  return [];
};

// Canonical "full international digits" a contact represents, using its
// calling_code to disambiguate. calling_code "60" + national "12345678" is
// +6012345678 -- distinct from a bare "12345678" contact that has no
// calling_code (that one only matches a bare, uncoded input).
const contactIntlForms = (m, cc) => {
  const out = [];
  m = (m == null ? "" : String(m)).trim();
  if (!m) return out;
  cc = (cc == null ? "" : String(cc)).trim();
  if (m.charAt(0) === "+") { out.push(m.slice(1)); return out; }
  if (cc) {
    if (m.indexOf(cc) === 0) out.push(m); // mobile already includes the code
    const nat = m.charAt(0) === "0" ? m.slice(1) : m;
    out.push(cc + nat);
    return out;
  }
  out.push(m); // no code: ambiguous national
  if (m.charAt(0) === "0") out.push(m.slice(1));
  return out;
};

const intersects = (a, b) => a.some((x) => b.indexOf(x) !== -1);

const pairs = [];
const customerIdSet = new Set();

if (lookupBy === "phone") {
  const contacts = Array.isArray(phoneContacts) ? phoneContacts : [];
  // One output pair per input number, preserving 1:1 ordering. Match a contact
  // only when its calling_code-qualified number equals the input's.
  for (const entry of (inputMap || [])) {
    const wanted = entry.intlForms || [];
    const match = contacts.find(
      (c) => c && intersects(contactIntlForms(c.mobile_number, c.calling_code), wanted)
    );
    if (match) {
      const cid = match.Customer_id || "";
      pairs.push({ mobile_number: match.mobile_number || entry.input, calling_code: match.calling_code != null ? String(match.calling_code) : "", customer_id: cid });
      if (cid) customerIdSet.add(cid);
    } else {
      pairs.push({ mobile_number: entry.input, calling_code: "", customer_id: "" });
    }
  }
} else {
  // Email fallback: single record via get-node.
  const contacts = getNodeToArray(emailRes);
  const match = contacts.length > 0 ? contacts[0] : null;
  if (match) {
    const cid = match.Customer_id || "";
    pairs.push({ mobile_number: match.mobile_number || "", calling_code: match.calling_code != null ? String(match.calling_code) : "", customer_id: cid });
    if (cid) customerIdSet.add(cid);
  } else {
    pairs.push({ mobile_number: "", calling_code: "", customer_id: "" });
  }
}

const customerIds = Array.from(customerIdSet);

return { pairs, customerIds };

const pairs = {{node:code_node_Eg4cGg3h.data.pairs}};
const customers = {{node:get_node_h9IHH6H7.data.data}} || [];

// search-node returns the rows array directly at .data.data
const list = Array.isArray(customers) ? customers : [];
const custById = {};
for (const c of list) {
  if (c && c.id != null) custById[String(c.id)] = c;
}

// Build a "working" full international number: calling_code + national, where
// the national part has any leading 0 stripped.
//
// If the stored mobile already begins with a recognizable calling code, we
// trust that embedded prefix and IGNORE the stored calling_code field (which
// may be inconsistent). e.g. calling_code "86" but mobile "60123456" -> the
// number already starts with "60", so we keep "60123456" and ignore the 86.
// All ASEAN / SE Asia calling codes.
const KNOWN_CC = ["60", "62", "63", "65", "66", "84", "95", "855", "856", "670", "673"];
const toWorkingNumber = (m, cc) => {
  m = (m == null ? "" : String(m)).trim();
  if (!m) return "";
  cc = (cc == null ? "" : String(cc)).trim();
  if (m.charAt(0) === "+") m = m.slice(1);
  // Already starts with the stored calling code -> leave as-is.
  if (cc && m.indexOf(cc) === 0 && m.length > cc.length) return m;
  // Already starts with any known calling code -> trust the embedded code.
  for (const k of KNOWN_CC) {
    if (m.indexOf(k) === 0 && m.length > k.length) return m;
  }
  if (!cc) return m;
  const nat = m.charAt(0) === "0" ? m.slice(1) : m;
  return cc + nat;
};

const result = (pairs || []).map((p) => {
  const c = p.customer_id ? custById[String(p.customer_id)] : null;
  return {
    mobile_number: toWorkingNumber(p.mobile_number, p.calling_code),
    customer_code: c && c.customer_id ? c.customer_id : "",
    customer_name: c && c.customer_com_name ? c.customer_com_name : ""
  };
});

return { result };
